(()=>{document.querySelectorAll(".note-body pre").forEach(e=>{const t=document.createElement("button");t.className="copy-btn",t.textContent="copy",t.addEventListener("click",()=>{const n=e.querySelector("code");navigator.clipboard.writeText(n.innerText).then(()=>{t.textContent="✓ copied",setTimeout(()=>t.textContent="copy",2e3)})}),e.style.position="relative",e.appendChild(t)})})()